SELECT reviewno, userno, commenta, createdat, contenttype, contentno
FROM review
WHERE contenttype = #{contentType}
AND contentno = #{contentNo}
ORDER BY createdat DESC

SELECT reviewno, userno, commenta, createdat, contenttype, contentno
FROM review
